// Parse y validar payload de CulqiLink webhook
const body = $json.body || $json;
const headers = $json.headers || {};

// Mapeo de precios a paquetes (montos en centimos)
const PACKAGES = {
  4900: { slug: 'ciencias-basicas', name: 'Ciencias Basicas' },
  7900: { slug: 'essalud-enam', name: 'EsSalud/ENAM' },
  11900: { slug: 'all-access', name: 'All Access' },
  3900: { slug: 'encaps', name: 'ENCAPS (Anki)' }
};

// Notion Page IDs por paquete
const NOTION_PAGES = {
  'ciencias-basicas': '2ee28574-650f-80c4-bdc2-f043e19f4f0b',
  'essalud-enam': '2f428574-650f-80d3-aafc-cb5374c44e14',
  'all-access': '2ed28574-650f-804e-85ce-ee3fc1bf4631',
  'encaps': '31e28574-650f-8058-b3f3-e6140913476e'
};

// Drive link para ENCAPS/Anki
const DRIVE_LINK = 'https://drive.google.com/drive/folders/1l2NYW_6ICSK1DWwlB3hT7WGW3YAc_J9T';

// Extraer datos del payload de CulqiLink
// CulqiLink puede enviar datos en diferentes formatos
// Adaptaremos segun el payload real que recibamos
const rawPayload = JSON.stringify(body, null, 2);

// Intentar extraer campos comunes
const amount = body.amount || body.total_amount || body.object?.amount || 0;
const email = body.email || body.customer_email || body.object?.email || body.metadata?.email || '';
const name = body.customer_name || body.metadata?.customer_name || body.object?.antifraud_details?.first_name || '';
const orderId = body.id || body.order_id || body.object?.id || `manual_${Date.now()}`;
const status = body.status || body.state || body.object?.outcome?.type || 'unknown';
const currency = body.currency_code || body.currency || body.object?.currency_code || 'PEN';

// Detectar paquete por monto
const pkg = PACKAGES[amount] || { slug: 'desconocido', name: `Monto: ${amount}` };
const notionPageId = NOTION_PAGES[pkg.slug] || '';
const includesAnki = pkg.slug === 'all-access' || pkg.slug === 'encaps';

// Timestamp Peru
const now = new Date();
const peruTime = new Date(now.getTime() - 5 * 60 * 60 * 1000);
const fechaPago = peruTime.toISOString().replace('T', ' ').substring(0, 19);

return {
  json: {
    // Datos procesados
    email,
    nombre: name,
    paquete: pkg.name,
    paqueteSlug: pkg.slug,
    monto: amount / 100, // Convertir centimos a soles
    montoRaw: amount,
    orderId,
    status,
    currency,
    fechaPago,
    notionPageId,
    includesAnki,
    driveLink: includesAnki ? DRIVE_LINK : '',
    // Debug: payload completo para ver estructura real
    rawPayload,
    // Validacion
    isValid: email !== '' && amount > 0,
    validationErrors: [
      ...(email === '' ? ['Email vacio'] : []),
      ...(amount === 0 ? ['Monto es 0'] : []),
      ...(pkg.slug === 'desconocido' ? [`Monto ${amount} no mapea a ningun paquete`] : [])
    ]
  }
};

// Formatear mensaje de venta para Slack con link Notion accionable
const data = $json;

// URLs de Notion por paquete (para que Andre/Nair hagan click y compartan)
const NOTION_URLS = {
  'ciencias-basicas': 'https://www.notion.so/2ee28574650f80c4bdc2f043e19f4f0b',
  'essalud-enam': 'https://www.notion.so/2f428574650f80d3aafccb5374c44e14',
  'all-access': 'https://www.notion.so/2ed28574650f804e85ceee3fc1bf4631',
  'encaps': 'https://www.notion.so/31e28574650f8058b3f3e6140913476e'
};

const notionUrl = NOTION_URLS[data.paqueteSlug] || '';
const driveLink = data.driveLink || '';

const slackMessage = {
  text: `Nueva venta: ${data.paquete} - ${data.email}`,
  blocks: [
    {
      type: 'header',
      text: {
        type: 'plain_text',
        text: 'Nueva Venta Resummo',
        emoji: true
      }
    },
    {
      type: 'section',
      fields: [
        { type: 'mrkdwn', text: `*Paquete:*\n${data.paquete}` },
        { type: 'mrkdwn', text: `*Monto:*\nS/${data.monto}` },
        { type: 'mrkdwn', text: `*Cliente:*\n${data.nombre || 'No proporcionado'}` },
        { type: 'mrkdwn', text: `*Fecha:*\n${data.fechaPago}` }
      ]
    },
    {
      type: 'divider'
    },
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: `*Email del comprador (copiar):*\n\`${data.email}\``
      }
    },
    {
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: `*Paso 1:* Abrir pagina Notion del paquete:\n<${notionUrl}|Abrir ${data.paquete} en Notion>\n\n*Paso 2:* Click \"Share\" arriba a la derecha → pegar email → invitar como Guest`
      }
    },
    ...(data.includesAnki ? [{
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: `*Paso 3 (Anki):* Compartir carpeta Drive con el mismo email:\n<${driveLink}|Abrir carpeta Anki en Drive>`
      }
    }] : []),
    {
      type: 'context',
      elements: [
        { type: 'mrkdwn', text: `Order: ${data.orderId}` }
      ]
    }
  ]
};

return { json: { ...data, slackMessage } };

// Preparar fila para Google Sheets — mapear a columnas detectadas por nodo nativo
// El nodo nativo detecta headers de fila 2: col_1, INGRESOS, col_3, col_4, col_5, col_6, col_7, col_8, col_9
const data = $json;

// Formatear fecha como DD/MM/YYYY
const parts = data.fechaPago.split(' ')[0].split('-');
const fechaFormateada = parts.length === 3 ? `${parts[2]}/${parts[1]}/${parts[0]}` : data.fechaPago;

return {
  json: {
    // Mapeo a nombres de columna detectados por nodo nativo Google Sheets
    'INGRESOS': fechaFormateada,
    'col_3': data.nombre || data.email,
    'col_4': data.paquete.toUpperCase(),
    'col_5': 'CULQILINK',
    'col_6': 'ANDRÉ',
    'col_7': data.monto,
    'col_8': '',
    'col_9': data.email,
    // Pasar datos originales para nodos siguientes
    ...data
  }
};
